    StrsHash *map = NULL;
    StrsHash *entry;
    char *key = NULL;
    char **resStrs = NULL;
    char ***result = NULL;
    int *colsSize = NULL;
    size_t i;

    // Create a hash map.
    for (i = 0; i < strsSize; i++) {
        entry = NULL;
        key = StrToKey(strs[i]);
        HASH_FIND_STR(map, key, entry);
        if (!entry) {
            entry = malloc(sizeof(StrsHash));
            entry->key = key;
            entry->size = 0;
            HASH_ADD_KEYPTR(hh, map, key, strlen(key), entry);
        } else {
            free(key);
        }
        entry->strs[entry->size++] = strs[i];
